import { createChatChannelPlugin, getChatChannelMeta } from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";

// Cast required because "pulseboard" is not yet in the registered ChatChannelId union;
// the meta fields below override whatever the lookup returns at runtime.
const meta = getChatChannelMeta("pulseboard" as Parameters<typeof getChatChannelMeta>[0]);

export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      ...meta,
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      blurb: "Connect to PulseBoard bulletin board messaging.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      /** Return configured account IDs from config (stub: always empty). */
      listAccountIds: () => [],
      /** Resolve a single account from config (stub: returns a placeholder). */
      resolveAccount: (_cfg, accountId) => ({
        accountId: accountId ?? "default",
        boardUrl: "",
        apiToken: "",
        username: "",
      }),
    },
    setup: {
      /** Apply CLI setup input to config (stub: returns config unchanged). */
      applyAccountConfig: ({ cfg }) => cfg,
    },
    gateway: {
      /** Start the PulseBoard connection for a single account (stub). */
      startAccount: async (ctx) => {
        ctx.log?.info?.(
          `[pulseboard] starting PulseBoard provider for account "${ctx.accountId}"`,
        );
      },
    },
    messaging: {
      normalizeTarget: (target: string) => target.trim(),
    },
  },
  outbound: {
    base: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
    },
    attachedResults: {
      channel: "pulseboard",
      sendText: async ({ to }) => ({
        to,
        messageId: `pb-${Date.now()}`,
      }),
    },
  },
});

